import React from "react";
import { Paper } from "@mui/material";
import { spacing } from '@/constants/ThemeConstants';

export interface PageCardProps {
  children: React.ReactNode;
  style?: React.CSSProperties;
}

// Paper sx (not inline style) so MUI applies theme-aware background/text
// colors in both light and dark modes.
export const PageCard: React.FunctionComponent<PageCardProps> = (props: PageCardProps) => {
  return (
    <Paper
      component="div"
      elevation={3}
      sx={{
        p: `${spacing.cardPadding}px`,
        mb: `${spacing.cardMarginBottom}px`,
        backgroundColor: 'background.paper',
        color: 'text.primary',
      }}
    >
      <div style={props.style}>
        {props.children}
      </div>
    </Paper>
  );
};

